int main() {
    // your code goes here
    int a, b, temp;

    // Read two integers from the user
    cin >> a >> b;

    // Swapping using a third variable
    temp = a;
    a = b;
    b = temp;
    cout << a << " " << b << endl;

    // Swapping back to original values using a third variable
    temp = a;
    a = b;
    b = temp;

    // Swapping without using a third variable (using arithmetic operations)
    a = a + b;
    b = a - b;
    a = a - b;
    cout << a << " " << b << endl;

    return 0;

}

